import React, { useEffect, useRef, useState } from "react";
import { Link } from "react-router-dom";

/* ==========================================================================
   INTERNAL ICON COMPONENTS (No external installs required)
   ==========================================================================
*/
const Icons = {
  Search: () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="11" cy="11" r="8"/><path d="m21 21-4.3-4.3"/></svg>
  ),
  Trophy: () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M6 9H4.5a2.5 2.5 0 0 1 0-5H6"/><path d="M18 9h1.5a2.5 2.5 0 0 0 0-5H18"/><path d="M4 22h16"/><path d="M10 14.66V17c0 .55-.47.98-.97 1.21C7.85 18.75 7 20.24 7 22"/><path d="M14 14.66V17c0 .55.47.98.97 1.21C16.15 18.75 17 20.24 17 22"/><path d="M18 2H6v7a6 6 0 0 0 12 0V2Z"/></svg>
  ),
  Users: () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"/><circle cx="9" cy="7" r="4"/><path d="M22 21v-2a4 4 0 0 0-3-3.87"/><path d="M16 3.13a4 4 0 0 1 0 7.75"/></svg>
  ),
  BarChart: () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><line x1="12" x2="12" y1="20" y2="10"/><line x1="18" x2="18" y1="20" y2="4"/><line x1="6" x2="6" y1="20" y2="16"/></svg>
  ),
  Code: () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="16 18 22 12 16 6"/><polyline points="8 6 2 12 8 18"/></svg>
  ),
  Zap: () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polygon points="13 2 3 14 12 14 11 22 21 10 12 10 13 2"/></svg>
  ),
  ArrowRight: () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg>
  )
};

/* ==========================================================================
   WARP SPEED BACKGROUND COMPONENT
   ==========================================================================
*/
const WarpBackground = () => {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    
    let width = window.innerWidth;
    let height = window.innerHeight;
    canvas.width = width;
    canvas.height = height;

    // Configuration
    const starCount = 200;
    const speed = 0.5; // Base speed
    const stars = [];

    // Initialize stars
    for (let i = 0; i < starCount; i++) {
      stars.push({
        x: Math.random() * width - width / 2,
        y: Math.random() * height - height / 2,
        z: Math.random() * width, // depth
        color: i % 3 === 0 ? "#818cf8" : i % 3 === 1 ? "#c084fc" : "#38bdf8" // Indigo, Purple, Cyan
      });
    }

    let animationFrameId;

    const render = () => {
      // Clear with trail effect
      ctx.fillStyle = "rgba(11, 17, 32, 0.4)"; // Dark blue-gray with opacity for trails
      ctx.fillRect(0, 0, width, height);

      const cx = width / 2;
      const cy = height / 2;

      stars.forEach((star) => {
        // Move star closer
        star.z -= speed * 10; // Speed multiplier

        // Reset if it passes screen
        if (star.z <= 0) {
          star.x = Math.random() * width - width / 2;
          star.y = Math.random() * height - height / 2;
          star.z = width;
        }

        // Project 3D to 2D
        const x = cx + (star.x / star.z) * width;
        const y = cy + (star.y / star.z) * height;
        
        // Calculate size based on depth (closer = bigger)
        const size = (1 - star.z / width) * 4;
        
        // Draw Star
        ctx.beginPath();
        ctx.fillStyle = star.color;
        // Using rectangles for a "tech/pixel" look
        ctx.fillRect(x, y, size, size); 
      });

      animationFrameId = requestAnimationFrame(render);
    };

    render();

    // Handle Resize
    const handleResize = () => {
      width = window.innerWidth;
      height = window.innerHeight;
      canvas.width = width;
      canvas.height = height;
    };

    window.addEventListener("resize", handleResize);

    return () => {
      cancelAnimationFrame(animationFrameId);
      window.removeEventListener("resize", handleResize);
    };
  }, []);

  return (
    <canvas 
      ref={canvasRef} 
      className="fixed top-0 left-0 w-full h-full pointer-events-none z-0 bg-[#0B1120]"
    />
  );
};


/* ==========================================================================
   MAIN HOME COMPONENT
   ==========================================================================
*/
export default function Home() {
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });

  // Handle mouse move for parallax effect on content
  const handleMouseMove = (e) => {
    const { clientX, clientY } = e;
    const centerX = window.innerWidth / 2;
    const centerY = window.innerHeight / 2;
    setMousePosition({
      x: (clientX - centerX) / 50, // Divide to soften the movement
      y: (clientY - centerY) / 50,
    });
  };

  return (
    <div 
      className="min-h-screen w-full relative overflow-x-hidden text-gray-900 dark:text-white selection:bg-indigo-500 selection:text-white"
      onMouseMove={handleMouseMove}
    >
      
      {/* 1. THE DYNAMIC BACKGROUND */}
      <WarpBackground />
      
      {/* 2. OVERLAY GRADIENTS (To make text readable) */}
      <div className="fixed inset-0 z-0 bg-gradient-to-b from-[#0B1120]/80 via-transparent to-[#0B1120] pointer-events-none"></div>
      <div className="fixed inset-0 z-0 bg-[radial-gradient(circle_at_center,transparent_0%,#0B1120_120%)] pointer-events-none"></div>

      {/* 3. MAIN CONTENT */}
      <div 
        className="relative z-10 flex flex-col items-center"
        style={{
          transform: `translate(${-mousePosition.x}px, ${-mousePosition.y}px)`,
          transition: "transform 0.1s ease-out"
        }}
      >
        
        {/* ================= HERO SECTION ================= */}
        <section className="flex flex-col items-center justify-center pt-32 pb-20 px-4 text-center w-full max-w-7xl mx-auto">
          
          {/* Badge */}
          <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-white/5 backdrop-blur-md border border-white/10 text-indigo-300 text-sm font-medium mb-8 shadow-[0_0_15px_rgba(99,102,241,0.3)] animate-pulse">
            <span className="relative flex h-2 w-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-indigo-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-indigo-500"></span>
            </span>
            Live Leaderboards Active
          </div>

          {/* Main Title */}
          <h1 className="max-w-5xl mx-auto text-6xl md:text-8xl font-extrabold tracking-tight mb-8">
            <span className="bg-clip-text text-transparent bg-gradient-to-r from-white via-indigo-200 to-indigo-500 drop-shadow-[0_0_30px_rgba(99,102,241,0.5)]">
              CPulse Tracker
            </span>
          </h1>

          <p className="max-w-2xl mx-auto text-lg md:text-xl text-gray-300 mb-12 leading-relaxed">
            The ultimate dashboard for competitive programmers. Track performance across <span className="text-white font-bold underline decoration-indigo-500 decoration-2 underline-offset-4">Codeforces</span> and <span className="text-white font-bold underline decoration-purple-500 decoration-2 underline-offset-4">LeetCode</span>.
          </p>

          {/* Buttons */}
          <div className="flex flex-col sm:flex-row items-center justify-center gap-5 w-full sm:w-auto">
            <Link
              to="/search"
              className="group relative w-full sm:w-auto overflow-hidden rounded-2xl bg-indigo-600 px-8 py-4 font-bold text-white shadow-[0_0_40px_rgba(79,70,229,0.4)] transition-all duration-300 hover:scale-105 hover:shadow-[0_0_60px_rgba(79,70,229,0.6)] focus:outline-none focus:ring-2 focus:ring-indigo-400 focus:ring-offset-2 focus:ring-offset-gray-900"
            >
              <div className="absolute inset-0 bg-gradient-to-r from-transparent via-white/20 to-transparent translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-700"></div>
              <div className="relative flex items-center justify-center gap-2">
                <Icons.Search />
                <span>Search User</span>
                <Icons.ArrowRight />
              </div>
            </Link>

            <div className="flex gap-4 w-full sm:w-auto">
              <Link
                to="/leaderboard"
                className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-6 py-4 rounded-2xl bg-white/5 backdrop-blur-md border border-white/10 text-white font-semibold transition-all hover:bg-white/10 hover:border-white/20 hover:-translate-y-1"
              >
                <div className="text-yellow-400"><Icons.Trophy /></div>
                Global Ranks
              </Link>

              <Link
                to="/class"
                className="flex-1 sm:flex-none flex items-center justify-center gap-2 px-6 py-4 rounded-2xl bg-white/5 backdrop-blur-md border border-white/10 text-white font-semibold transition-all hover:bg-white/10 hover:border-white/20 hover:-translate-y-1"
              >
                <div className="text-blue-400"><Icons.Users /></div>
                Class Ranks
              </Link>
            </div>
          </div>
        </section>

        {/* ================= FEATURES SECTION ================= */}
        <section className="py-20 px-4 w-full max-w-7xl mx-auto">
          <div className="text-center mb-16">
            <h2 className="text-3xl md:text-5xl font-bold text-white mb-6">
              Level up your game
            </h2>
            <p className="text-gray-400 text-lg">
              Built for speed, accuracy, and competition.
            </p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {/* Feature 1 */}
            <div className="group relative p-8 rounded-3xl bg-gray-900/40 backdrop-blur-xl border border-white/5 transition-all duration-300 hover:-translate-y-2 hover:bg-gray-800/60 hover:border-indigo-500/30 hover:shadow-[0_10px_40px_-10px_rgba(79,70,229,0.2)]">
              <div className="inline-flex items-center justify-center w-14 h-14 rounded-2xl bg-indigo-500/10 text-indigo-400 mb-6 group-hover:scale-110 transition-transform">
                <Icons.BarChart />
              </div>
              <h3 className="text-xl font-bold text-white mb-3">Comprehensive Stats</h3>
              <p className="text-gray-400 leading-relaxed">
                Live Codeforces ratings, rank changes, and solved problems visualized instantly.
              </p>
            </div>

            {/* Feature 2 */}
            <div className="group relative p-8 rounded-3xl bg-gray-900/40 backdrop-blur-xl border border-white/5 transition-all duration-300 hover:-translate-y-2 hover:bg-gray-800/60 hover:border-blue-500/30 hover:shadow-[0_10px_40px_-10px_rgba(59,130,246,0.2)]">
              <div className="inline-flex items-center justify-center w-14 h-14 rounded-2xl bg-blue-500/10 text-blue-400 mb-6 group-hover:scale-110 transition-transform">
                <Icons.Code />
              </div>
              <h3 className="text-xl font-bold text-white mb-3">Competitive Context</h3>
              <p className="text-gray-400 leading-relaxed">
                Create custom leaderboards. Compare against your friends and classmates in real-time.
              </p>
            </div>

            {/* Feature 3 */}
            <div className="group relative p-8 rounded-3xl bg-gray-900/40 backdrop-blur-xl border border-white/5 transition-all duration-300 hover:-translate-y-2 hover:bg-gray-800/60 hover:border-amber-500/30 hover:shadow-[0_10px_40px_-10px_rgba(245,158,11,0.2)]">
              <div className="inline-flex items-center justify-center w-14 h-14 rounded-2xl bg-amber-500/10 text-amber-400 mb-6 group-hover:scale-110 transition-transform">
                <Icons.Zap />
              </div>
              <h3 className="text-xl font-bold text-white mb-3">Blazing Fast</h3>
              <p className="text-gray-400 leading-relaxed">
                Zero-latency caching layer ensures you never hit API limits while tracking progress.
              </p>
            </div>
          </div>
        </section>

        {/* ================= FOOTER ================= */}
        <footer className="w-full border-t border-white/10 bg-black/20 backdrop-blur-lg mt-10">
          <div className="max-w-7xl mx-auto py-8 px-4 flex flex-col md:flex-row items-center justify-between gap-4">
            <p className="text-gray-500 text-sm">
              © {new Date().getFullYear()} CPulse Tracker.
            </p>
            <div className="flex items-center gap-6 text-sm text-gray-500">
               <span className="hover:text-white cursor-pointer transition-colors">Privacy</span>
               <span className="hover:text-white cursor-pointer transition-colors">Terms</span>
               <a href="https://github.com" target="_blank" rel="noreferrer" className="hover:text-white transition-colors">GitHub</a>
            </div>
          </div>
        </footer>

      </div>
    </div>
  );
}
